t.script:
/*  */
(function () {
    // ── Restore values after validation error ──
    var INIT_COMPANY  = '<t t-esc="form_data.get(\'training_company_id\', \'\')"/>';
    var INIT_PROGRAM  = '<t t-esc="form_data.get(\'training_program_id\', \'\')"/>';
    var INIT_WEEK     = '<t t-esc="form_data.get(\'training_week_id\', \'\')"/>';
    var INIT_LEVEL    = '<t t-esc="form_data.get(\'university_group\', \'\')"/>';

    // ── Helpers ──
    function fmtDate(s) {
        if (!s) return '';
        var d = new Date(s);
        return d.toLocaleDateString('en-GB', {day:'numeric', month:'short'});
    }
    function getJSON(url, cb) {
        var x = new XMLHttpRequest();
        x.open('GET', url, true);
        x.onload = function () {
            try { cb(JSON.parse(x.responseText)); } catch(e) { cb([]); }
        };
        x.onerror = function () { cb([]); };
        x.send();
    }
    function show(id) { document.getElementById(id).style.display = ''; }
    function hide(id) { document.getElementById(id).style.display = 'none'; }

    // ── National ID counter ──
    var nidEl = document.getElementById('national_id_input');
    var nidCt = document.getElementById('nid_counter');
    if (nidEl) {
        function refreshCounter() {
            var n = nidEl.value.length;
            nidCt.textContent = n + ' / 14 digits';
            nidCt.style.color = n === 14 ? '#198754' : '#6c757d';
        }
        nidEl.addEventListener('input', refreshCounter);
        refreshCounter();
    }

    // ── Build week cards ──
    function buildWeekCards(weeks, selectedId) {
        var box = document.getElementById('week_cards');
        var inp = document.getElementById('inp_week');
        box.innerHTML = '';
        if (!weeks || !weeks.length) {
            box.innerHTML = '<p class="text-muted">No weeks configured for this program.</p>';
            return;
        }
        weeks.forEach(function (w) {
            var sel = String(w.id) === String(selectedId);
            var card = document.createElement('div');
            card.style.cssText = [
                'width:160px', 'border-radius:10px', 'padding:14px 12px',
                'text-align:center', 'cursor:' + (w.full ? 'not-allowed' : 'pointer'),
                'border:2px solid ' + (sel ? '#0e6b6b' : (w.full ? '#dee2e6' : '#ced4da')),
                'background:'      + (sel ? '#e8f7f7' : (w.full ? '#f8f9fa' : '#ffffff')),
                'opacity:'         + (w.full ? '0.6' : '1'),
                'transition:all .15s', 'user-select:none',
            ].join(';');
            card.innerHTML =
                '<div style="font-weight:700;color:#0d2137;font-size:.95rem;">Week ' + w.number + '</div>' +
                '<div style="font-size:.78rem;color:#555;margin:4px 0;">' + fmtDate(w.start) + ' \u2013 ' + fmtDate(w.end) + '</div>' +
                '<div style="font-size:.8rem;font-weight:600;margin-top:6px;color:' + (w.full ? '#dc3545' : '#198754') + ';">' +
                    (w.full ? '&#128308; FULL' : '&#128994; ' + w.left + ' OPEN') +
                '</div>';
            if (!w.full) {
                card.addEventListener('click', function () {
                    document.querySelectorAll('#week_cards > div').forEach(function (c) {
                        c.style.border     = '2px solid #ced4da';
                        c.style.background = '#ffffff';
                    });
                    card.style.border     = '2px solid #0e6b6b';
                    card.style.background = '#e8f7f7';
                    inp.value = w.id;
                });
                if (sel) { inp.value = w.id; }
            }
            box.appendChild(card);
        });
    }

    // ── Load weeks ──
    function loadWeeks(pid, selWeek) {
        hide('div_weeks');
        show('div_weeks_loading');
        document.getElementById('inp_week').value = '';
        getJSON('/training/ajax/weeks?program_id=' + pid, function (weeks) {
            hide('div_weeks_loading');
            show('div_weeks');
            buildWeekCards(weeks, selWeek || '');
        });
    }

    // ── Show year level badges ──
    function showLevels(level_ids) {
        var box = document.getElementById('level_badges');
        box.innerHTML = '';
        if (level_ids && level_ids.length) {
            level_ids.forEach(function (l) {
                var b = document.createElement('span');
                b.style.cssText = 'background:#0e6b6b;color:#fff;padding:5px 14px;border-radius:20px;font-size:.85rem;';
                b.textContent = l.name;
                box.appendChild(b);
            });
            show('div_levels');
        } else {
            hide('div_levels');
        }
    }

    // ── Load programs for company ──
    function loadPrograms(cid, lid, selProgram, selWeek, showAlert) {
        var sel = document.getElementById('sel_program');
        sel.innerHTML = '<option value="">Select Program</option>';
        hide('div_program');
        hide('div_levels');
        hide('div_weeks');
        if (!cid) return;

        var url = '/training/ajax/programs?company_id=' + cid + (lid ? '&level_id=' + lid : '');
        getJSON(url, function (programs) {
            if (!programs || !programs.length) {
                show('div_program');
                if (showAlert) {
                    var companyName = selCompany.options[selCompany.selectedIndex].text;
                    alert('No training programs are available for your year level at ' + companyName + '. Please contact your coordinator or choose a different company.');
                }
                return;
            }
            programs.forEach(function (p) {
                var o = document.createElement('option');
                o.value = p.id;
                o.textContent = p.name + (p.code ? ' (' + p.code + ')' : '');
                if (String(p.id) === String(selProgram)) o.selected = true;
                sel.appendChild(o);
            });
            show('div_program');

            var autoId = selProgram || (programs.length === 1 ? programs[0].id : null);
            if (autoId) {
                sel.value = String(autoId);
                var prog = programs.find(function(p){ return String(p.id) === String(autoId); });
                if (prog) {
                    showLevels(prog.level_ids);
                    loadWeeks(autoId, selWeek);
                }
            }
        });
    }

    // ── Student lookup by university ID ──
    var univIdInput = document.getElementById('university_id_input');
    var lookupStatus = document.getElementById('student_lookup_status');
    var _resolvedLevelId = '';  // stores level id from student lookup

    function doStudentLookup() {
        var uid = univIdInput.value.trim();
        if (!uid) return;
        lookupStatus.textContent = 'Looking up...';
        lookupStatus.style.color = '#6c757d';
        getJSON('/training/ajax/student?university_id=' + encodeURIComponent(uid), function (data) {
            if (data.found) {
                // Show auto-filled section
                show('div_student_info');
                hide('div_not_found');
                show('div_training_section');
                document.getElementById('btn_submit').style.display = '';
                lookupStatus.textContent = '&#10003; Student found';
                lookupStatus.style.color = '#198754';

                // Fill name
                var nameInp = document.getElementById('inp_student_name');
                if (nameInp) nameInp.value = data.name || '';

                // Fill phone
                var phoneInp = document.getElementById('inp_phone');
                if (phoneInp) phoneInp.value = data.phone || '';

                // Fill national ID
                var nidInp = document.getElementById('national_id_input');
                if (nidInp) {
                    nidInp.value = data.national_id || '';
                    if (nidCt) {
                        var n = nidInp.value.length;
                        nidCt.textContent = n + ' / 14 digits';
                        nidCt.style.color = n === 14 ? '#198754' : '#6c757d';
                    }
                }

                // Fill university
                var univSel = document.getElementById('sel_university');
                if (univSel && data.university_key) univSel.value = data.university_key;

                // Fill year level + trigger program reload
                var levelSel = document.getElementById('sel_level');
                if (levelSel && data.level_id) {
                    levelSel.value = data.level_id;
                    _resolvedLevelId = data.level_id;
                }
                // Always reload programs with resolved level
                var cid = document.getElementById('sel_company') ? document.getElementById('sel_company').value : '';
                if (cid) loadPrograms(cid, _resolvedLevelId || data.level_id, '', '', false);

            } else {
                // Not found — block registration
                hide('div_student_info');
                show('div_not_found');
                hide('div_training_section');
                document.getElementById('btn_submit').style.display = 'none';
                lookupStatus.textContent = '&#10060; Not registered';
                lookupStatus.style.color = '#dc3545';
            }
        });
    }

    if (univIdInput) {
        univIdInput.addEventListener('blur', doStudentLookup);
        univIdInput.addEventListener('keydown', function(e) {
            if (e.key === 'Enter') { e.preventDefault(); doStudentLookup(); }
        });
    }

    // Show student info div if form_data exists (re-render after error)
    var INIT_UNIV_ID = '<t t-esc="form_data.get(\'university_id\', \'\')"/>';
    if (INIT_UNIV_ID) {
        show('div_student_info');
        show('div_training_section');
        document.getElementById('btn_submit').style.display = '';
    }

    // ── Wire events ──
    var selCompany = document.getElementById('sel_company');
    var selProgram = document.getElementById('sel_program');
    var selLevel   = document.getElementById('sel_level');

    if (selLevel) {
        selLevel.addEventListener('change', function () {
            _resolvedLevelId = this.value;
            var cid = selCompany.value;
            if (cid) {
                loadPrograms(cid, this.value, '', '', true);
            }
        });
    }

    selCompany.addEventListener('change', function () {
        var lid = _resolvedLevelId || (document.getElementById('sel_level') ? document.getElementById('sel_level').value : '');
        loadPrograms(this.value, lid, '', '', true);
    });

    selProgram.addEventListener('change', function () {
        var pid = this.value;
        if (!pid) { hide('div_levels'); hide('div_weeks'); return; }
        loadWeeks(pid, '');
        var cid = selCompany.value;
        var lid = document.getElementById('sel_level') ? document.getElementById('sel_level').value : '';
        var url = '/training/ajax/programs?company_id=' + cid + (lid ? '&level_id=' + lid : '');
        getJSON(url, function (programs) {
            var prog = programs.find(function(p){ return String(p.id) === String(pid); });
            if (prog) showLevels(prog.level_ids);
        });
    });

    // ── Restore state on validation re-render ──
    if (INIT_COMPANY) {
        loadPrograms(INIT_COMPANY, INIT_LEVEL, INIT_PROGRAM, INIT_WEEK, false);
    }

})();
/*  */
